import{_ as t,o as n,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"63. Union Matters","description":"","frontmatter":{"title":"63. Union Matters","eba":"Mental Health Services 2024-2028","topics":["union-matters"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/workplace-rights/63-union-matters.md","filePath":"ebas/mental-health/common-terms/workplace-rights/63-union-matters.md"}'),r={name:"ebas/mental-health/common-terms/workplace-rights/63-union-matters.md"};function i(s,e,l,p,c,g){return n(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_63-union-matters" tabindex="-1">63. Union Matters <a class="header-anchor" href="#_63-union-matters" aria-label="Permalink to &quot;63. Union Matters&quot;">​</a></h1><p><strong>63.1</strong> Access to Employees – General The Union will have access to Employees for any process arising under this Agreement.</p><p><strong>63.2</strong> Access to Employees – Electronic communication The Employer will ensure that:</p><p><strong>(a)</strong> emails from the Union domain name are not blocked or restricted by or on behalf of the Employer, except in respect of any individual Employee who has made a written request to the Employer to block such emails</p><p><strong>(b)</strong> emails from Employees to the Union are not blocked or restricted by or on behalf of the Employer</p><p><strong>(c)</strong> access from health service computers and like devices to Union websites and online information is not blocked, or limited</p><p><strong>(d)</strong> where a genuine security concern arises regarding the above, the Employer will immediately notify the Union to enable the security concern to be addressed.</p><p><strong>63.3</strong> Access to Employees – Orientation</p><p><strong>(a)</strong> For the purposes of facilitating the orientation of new Employees and in particular to familiarise such Employees with the operation of this Agreement, the HACSU and the ANMF shall be provided, in writing on a quarterly basis, with the dates, times and venues of any orientation/induction program involving new Employees and be permitted to attend and address the new Employees. If the dates of these programs are fixed in advance for a regular day and time then a list will be sent to the HACSU and the ANMF as soon as such dates are fixed</p><p><strong>(b)</strong> Where the dates of orientation/induction programs are not fixed in advance, HACSU and ANMF will receive reasonable notification of at least 14 days to enable a representative to attend and address.</p><p><strong>(c)</strong> Those covered by this Agreement acknowledge the increasing role that technology plays in orientation / induction. An Employer and Union may agree to an alternative means by which the Union can access new Employees who are eligible to be members of the Union, including where orientation / induction programs are conducted on-line or the Union cannot reasonably attend the premises. Any alternative means of access agreed to between the Employer and Union under this clause must be consistent with the Act.</p><p><strong>63.4</strong> Delegates and Occupational Health &amp; Safety Representatives NOTE: Additional rights of HSRs and Deputy HSRs are contained in the OHS Act.</p><p><strong>(a)</strong> In this subclause 63.4</p><p><strong>(i)</strong> Representative means a Union Delegate, Deputy HSR or HSR</p><p><strong>(ii)</strong> Relevant Employee means: <strong>(A)</strong> In the case of a Union Delegate, members of the Union and any other persons eligible to be members of the Union; and <strong>(B)</strong> In the case of a HSR, members of the designated work group eligible to be represented by the HSR.</p><p><strong>(iii)</strong> Union Delegate means an Employee who presents themselves as a delegate of a Union to their Employer, subject to: <strong>(A)</strong> the relevant Union&#39;s applicable policies (if any); and <strong>(B)</strong> the relevant Union confirming in writing the Employee&#39;s status as a Union Delegate.</p><p><strong>(b)</strong> A Union Delegate is entitled to:</p><p><strong>(i)</strong> represent the industrial interests of Relevant Employees, including in disputes between that person and the Employer; and</p><p><strong>(ii)</strong> reasonable communication with members of the Union, and any other persons eligible to be members of the Union, in relation to their industrial interests. Communication may occur during working hours or work breaks, or before or after work.</p><p><strong>(c)</strong> For the purposes of representing the industrial interests of members of the Union and any other persons eligible to be members of the Union, a Union Delegate is entitled to reasonable access to the workplace of the Employer and any workplace facilities where work of the Employer is being undertaken.</p><p><strong>(d)</strong> A Representative is entitled to reasonable time release from duty to:</p><p><strong>(i)</strong> attend to matters relating to industrial, occupational health and safety or other relevant matters such as assisting with grievance procedures and attending committee meetings</p><p><strong>(ii)</strong> access reasonable preparation time before meetings with management disciplinary or grievance meetings with a Relevant Employee</p><p><strong>(iii)</strong> in the case of a Union delegate: <strong>(A)</strong> appear as a witness or participate in conciliation or arbitration, before the commission; and/or <strong>(B)</strong> present information on the Union at orientation sessions for new Employees.</p><p><strong>(e)</strong> A Representative required to attend management or consultative meetings outside of paid time will be paid to attend.</p><p><strong>(f)</strong> A Representative will be provided with access to facilities such as:</p><p><strong>(i)</strong> telephones</p><p><strong>(ii)</strong> computers</p><p><strong>(iii)</strong> email</p><p><strong>(iv)</strong> noticeboards</p><p><strong>(v)</strong> meeting rooms or areas to hold discussions that are fit for purpose, private and accessible by the workplace delegate and eligible employees</p><p><strong>(vi)</strong> Wi-Fi</p><p><strong>(vii)</strong> a lockable filing cabinet or other secure document storage area; and</p><p><strong>(viii)</strong> office facilities and equipment including printers, scanners and photocopiers in a manner that does not adversely affect service delivery and work requirements of the Employer. In the case of an HSR or Deputy HSR, facilities will include other facilities as necessary to enable them to perform their functions as prescribed under the OHS Act.</p><p><strong>(g)</strong> Except as otherwise required by law, the Employer will not:</p><p><strong>(i)</strong> unreasonably fail or reuse to deal with a Union Delegate; or</p><p><strong>(ii)</strong> knowingly or recklessly make a false or misleading representation to a Union Delegate; or</p><p><strong>(iii)</strong> unreasonably hinder, obstruct or prevent a Union Delegate from exercising any of their rights insofar as the Union Delegate is acting in their capacity as a Representative.</p><p><strong>63.5</strong> Noticeboard</p><p><strong>(a)</strong> A noticeboard for the Union’s use will be readily accessible in each ward/unit/work area or nearest staff room where persons eligible to be members of the Union are employed.</p><p><strong>(b)</strong> The Union and members covered by this Agreement will, during the life of this Agreement, consult over the development of an electronic noticeboard managed by the Union.</p><p><strong>63.6</strong> Meeting Space In the absence of agreement on a location for the holding of Union meetings, the room where one or more of the Employees who may participate in the meeting ordinarily take meal or other breaks will be the meeting room for the purpose of union meetings. Nothing in this clause is intended to override the operation of the Act.</p><p><strong>63.7</strong> Secondment to the Union The Employer will, on application, grant leave without pay in writing, to an Employee for the purpose of secondment to work for the Union subject to the Employer’s reasonable operational requirements. Such absence will not break service but not count as service for LSL purposes.</p><p><strong>63.8</strong> Employees holding union official positions The Employer will, on application by the Union, grant leave without loss of pay to an Employee for the purpose of fulfilling their duties as an official of the Council, Executive Council, Branch Committee of Management and National Council, however so named.</p><p><strong>63.9</strong> Union Training NOTE: an HSR and Deputy HSR appointed under the OHS Act may be entitled to any additional training in accordance with the OHS Act.</p><p><strong>(a)</strong> In order to encourage co-operative workplace relations and facilitate the operation of this Agreement, Employees who have been selected by their union(s) to attend training courses on industrial relations and/or health and safety will be entitled to a maximum of five days’ paid leave per calendar year (Noting that leave for HSRs and Deputy HSR training is a distinct entitlement under the OHS Act).</p><p><strong>(b)</strong> Leave in excess of five days and up to ten days may be granted in a calendar year subject to the total leave being granted in that year and in the subsequent year not exceeding ten days.</p><p><strong>(c)</strong> The granting of leave will be subject to the Employer’s operational requirements. The granting of leave will not be unreasonably withheld.</p><p><strong>(d)</strong> Leave under this subclause is granted on the following conditions:</p><p><strong>(i)</strong> applications are accompanied by a statement from the Union advising that it has nominated the Employee or supports the application</p><p><strong>(ii)</strong> the training is conducted by the Union, an association of unions or accredited training provider; and</p><p><strong>(iii)</strong> the application is made as early as practicable and not less than two (2) weeks before the training.</p><p><strong>(e)</strong> The Employee will be paid ‘ordinary time earnings’ where ordinary pay is the rate of pay for normal rostered hours (set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>) plus experience/service payments plus allowances which are deemed pursuant to this Agreement to be part of pay for all purposes, but excluding shift work, overtime and other allowances.</p><p><strong>(f)</strong> Leave in accordance with this clause may include necessary travelling time in normal hours immediately before or after the course.</p><p><strong>(g)</strong> Leave granted under this clause will count as service for all purposes of this Agreement.</p><p><strong>(h)</strong> Expenses associated with attendance at training courses, including fares, accommodation and meal costs are not the responsibility of the Employer.</p><p>Plain language terms: union rep, delegate, union representative, right of entry.</p>',57)])])}const m=t(r,[["render",i]]);export{d as __pageData,m as default};
